function parse_xml(xml_string) {
    // Check type
    if (typeof xml_string !== 'string') {
        throw new TypeError("xml_string must be a string");
    }
    // Reject empty strings
    if (xml_string.trim() === "") {
        throw new Error("empty xml");
    }

    // Reject DTD/ENTITY constructs (case-insensitive)
    const upper = xml_string.toUpperCase();
    if (upper.includes("<!DOCTYPE") || upper.includes("<!ENTITY")) {
        throw new Error("DTD/ENTITY not allowed");
    }

    try {
        const parser = new DOMParser();
        const doc = parser.parseFromString(xml_string, "text/xml");
        // Check for parser errors (xmldom produces <parsererror>)
        const parseErrors = doc.getElementsByTagName("parsererror");
        if (parseErrors.length > 0) {
            throw new Error("invalid xml");
        }
        // Also check that there is a document element
        if (!doc.documentElement) {
            throw new Error("invalid xml");
        }
        // Add a 'tag' property to match the test's expectation
        const root = doc.documentElement;
        root.tag = root.tagName;
        return root;
    } catch (e) {
        // Re-throw custom errors; wrap other errors
        if (e.message === "invalid xml") {
            throw e;
        }
        throw new Error("invalid xml");
    }
}

