function getEncryptionKey(data, key) {
    // Validate types
    if (!(data instanceof Buffer || data instanceof Uint8Array)) {
        throw new TypeError('data must be a Buffer or Uint8Array');
    }
    if (!(key instanceof Buffer || key instanceof Uint8Array)) {
        throw new TypeError('key must be a Buffer or Uint8Array');
    }

    // Validate key length for AES (16, 24, or 32 bytes)
    if (key.length !== 16 && key.length !== 24 && key.length !== 32) {
        throw new Error('Invalid key length');
    }

    const blockSize = 16;
    const iv = crypto.randomBytes(blockSize);

    // Determine cipher algorithm based on key length
    let algorithm;
    if (key.length === 16) {
        algorithm = 'aes-128-cbc';
    } else if (key.length === 24) {
        algorithm = 'aes-192-cbc';
    } else {
        algorithm = 'aes-256-cbc';
    }

    // Pad data to block size using PKCS7
    const padLength = blockSize - (data.length % blockSize);
    const padded = Buffer.alloc(data.length + padLength);
    data.forEach((byte, i) => padded[i] = byte);
    padded.fill(padLength, data.length);

    // Encrypt
    const cipher = crypto.createCipheriv(algorithm, key, iv);
    const encrypted = Buffer.concat([cipher.update(padded), cipher.final()]);

    // Prepend IV to ciphertext
    return Buffer.concat([iv, encrypted]);
}

